CREATE OR REPLACE FUNCTION what_quarter_is(date_in DATE, start_month INT) 
RETURNS INT AS $$
DECLARE
    month_num INT;
    adjusted_month INT;
BEGIN
    month_num := EXTRACT(MONTH FROM date_in);
    adjusted_month := 1 + ((month_num - start_month + 12) % 12);
    RETURN CEILING(adjusted_month / 3.0);
END;
$$ LANGUAGE plpgsql;

