CREATE OR REPLACE FUNCTION token_lcp(text_array text[]) RETURNS text AS $$
DECLARE
    result text := '';
    current_token text;
    all_match boolean;
    i integer := 1;
    first_row_tokens text[];
BEGIN
    -- If array is empty, return empty string
    IF array_length(text_array, 1) IS NULL THEN
        RETURN '';
    END IF;

    -- Split the first row into tokens
    first_row_tokens := string_to_array(text_array[1], '#');

    -- For each token in the first row
    WHILE i <= array_length(first_row_tokens, 1) LOOP
        current_token := first_row_tokens[i];
        all_match := true;

        -- Check if this token matches in all rows
        FOR j IN 2..array_length(text_array, 1) LOOP
            DECLARE
                row_tokens text[] := string_to_array(text_array[j], '#');
            BEGIN
                -- If this row doesn't have enough tokens or the token doesn't match
                IF i > array_length(row_tokens, 1) OR row_tokens[i] <> current_token THEN
                    all_match := false;
                    EXIT;
                END IF;
            END;
        END LOOP;

        -- If token matches in all rows, add it to result
        IF all_match THEN
            IF result = '' THEN
                result := current_token;
            ELSE
                result := result || '#' || current_token;
            END IF;
            i := i + 1;
        ELSE
            EXIT;
        END IF;
    END LOOP;

    -- Add the trailing # if we have any matches
    IF result <> '' THEN
        result := result || '#';
    END IF;

    RETURN result;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE AGGREGATE token_lcp_agg(text) (
    SFUNC = array_append,
    STYPE = text[],
    FINALFUNC = token_lcp,
    INITCOND = '{}'
);

