-- First, create a unique index to ensure that each match_id and team_id combination has only one score
CREATE UNIQUE INDEX unique_match_team_score ON match_results (match_id, team_id, score);

-- Then, create a trigger function to enforce the constraint
CREATE OR REPLACE FUNCTION enforce_match_result_consistency()
RETURNS TRIGGER AS $$
BEGIN
    -- Check if there are existing records with the same match_id and team_id but different score
    IF EXISTS (
        SELECT 1 
        FROM match_results 
        WHERE match_id = NEW.match_id 
          AND team_id = NEW.team_id 
          AND score <> NEW.score
    ) THEN
        RAISE EXCEPTION 'Inconsistent score for match_id % and team_id %', NEW.match_id, NEW.team_id;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create the trigger
CREATE TRIGGER check_match_result_consistency
BEFORE INSERT OR UPDATE ON match_results
FOR EACH ROW EXECUTE FUNCTION enforce_match_result_consistency();

