CREATE OR REPLACE FUNCTION update_school_inventory_after_supply() 
RETURNS TRIGGER 
LANGUAGE plpgsql AS $trigger$
BEGIN
    -- Check if the inventory record exists
    IF EXISTS (
        SELECT 1 FROM school_inventory 
        WHERE cdscode = NEW.cdscode AND supply_name = NEW.supply_name
    ) THEN
        -- Update existing inventory record
        UPDATE school_inventory
        SET quantity = quantity + NEW.quantity,
            last_updated = CURRENT_TIMESTAMP
        WHERE cdscode = NEW.cdscode AND supply_name = NEW.supply_name;
    ELSE
        -- Insert new inventory record if it doesn't exist
        INSERT INTO school_inventory (
            cdscode, 
            supply_name, 
            quantity, 
            last_updated
        ) VALUES (
            NEW.cdscode, 
            NEW.supply_name, 
            NEW.quantity, 
            CURRENT_TIMESTAMP
        );
    END IF;

    RETURN NEW;
END;
$trigger$;

