DECLARE
    v_year NUMBER;
    v_week VARCHAR2(2);
    v_home_team_wins NUMBER;
    v_away_team_wins NUMBER;
    v_draws NUMBER;
    v_total_matches NUMBER;
BEGIN
    FOR match_rec IN (
        SELECT EXTRACT(YEAR FROM "date") AS "year",
               TO_CHAR("date", 'IW') AS "week",
               SUM(CASE WHEN "home_team_goal" > "away_team_goal" THEN 1 ELSE 0 END) AS home_wins,
               SUM(CASE WHEN "home_team_goal" < "away_team_goal" THEN 1 ELSE 0 END) AS away_wins,
               SUM(CASE WHEN "home_team_goal" = "away_team_goal" THEN 1 ELSE 0 END) AS draws,
               COUNT(*) AS total_matches
        FROM "Match"
        GROUP BY EXTRACT(YEAR FROM "date"),
                 TO_CHAR("date", 'IW')
        ORDER BY "year", "week"
    )
    LOOP
        v_year := match_rec."year";
        v_week := match_rec."week";
        v_home_team_wins := match_rec.home_wins;
        v_away_team_wins := match_rec.away_wins;
        v_draws := match_rec.draws;
        v_total_matches := match_rec.total_matches;
        -- Add processing logic here
    END LOOP;
END;

DECLARE 
    v_molecule_id NVARCHAR2(512);
    v_label NCLOB;
    v_atom_id NVARCHAR2(512);
    v_element NCLOB;
    v_atom_id2 NVARCHAR2(512);
    v_bond_id NVARCHAR2(512);
    v_bond_type NCLOB;

    CURSOR molecule_data IS
        SELECT m."molecule_id",
               m."label",
               a."atom_id",
               a."element",
               c."atom_id2",
               b."bond_id",
               b."bond_type"
        FROM "molecule" m
        INNER JOIN "atom" a ON m."molecule_id" = a."molecule_id"
        INNER JOIN "connected" c ON a."atom_id" = c."atom_id"
        INNER JOIN "bond" b ON c."bond_id" = b."bond_id"
        ORDER BY m."molecule_id", a."atom_id", c."atom_id2";
BEGIN
    OPEN molecule_data;
    LOOP
        FETCH molecule_data INTO v_molecule_id, v_label, v_atom_id, v_element, v_atom_id2, v_bond_id, v_bond_type;
        EXIT WHEN molecule_data%NOTFOUND;
        -- Add processing logic here using the variables
    END LOOP;
    CLOSE molecule_data;
END;
